import { Router } from 'express';
import JSZip from 'jszip';
import { verifyToken } from '../lib/auth';

const router = Router();

const GEMINI_EXT_FILES: { name: string; data: Buffer; binary?: boolean }[] = [
  { name: "manifest.json",          data: Buffer.from("", "base64") },
  { name: "background.js",          data: Buffer.from("", "base64") },
  { name: "gemini_content.js",      data: Buffer.from("", "base64") },
  { name: "site_bridge_gemini.js",  data: Buffer.from("", "base64") },
  { name: "popup.html",             data: Buffer.from("", "base64") },
  { name: "popup.js",               data: Buffer.from("", "base64") },
  { name: "icon16.png",             data: Buffer.from("", "base64"), binary: true },
  { name: "icon48.png",             data: Buffer.from("", "base64"), binary: true },
  { name: "icon128.png",            data: Buffer.from("", "base64"), binary: true },
];

// GET /api/extension/gemini-download?token=<jwt>
router.get('/gemini-download', async (req, res) => {
  try {
    const rawToken = (req.query.token as string) ||
                     (req.headers['authorization'] || '').replace(/^Bearer\s+/i, '');
    if (!rawToken) { res.status(401).json({ error: 'Authentication required' }); return; }
    let jwt = rawToken;
    const colonIdx = rawToken.indexOf(':');
    if (colonIdx > 0 && colonIdx < 10) { jwt = rawToken.substring(colonIdx + 1); }
    const payload = verifyToken(jwt);
    if (!payload || !payload.userId) { res.status(401).json({ error: 'Invalid or expired token' }); return; }
    const zip = new JSZip();
    for (const file of GEMINI_EXT_FILES) {
      if (file.binary) { zip.file(file.name, file.data, { binary: true }); }
      else { zip.file(file.name, file.data.toString('utf8')); }
    }
    const zipBuffer = await zip.generateAsync({ type: 'nodebuffer', compression: 'DEFLATE' });
    res.setHeader('Content-Type', 'application/zip');
    res.setHeader('Content-Disposition', 'attachment; filename="bunnyflow-gemini-extension.zip"');
    res.send(zipBuffer);
  } catch (err) {
    console.error('[gemini-ext]', err);
    res.status(500).json({ error: 'Failed to generate extension' });
  }
});

export default router;
